mapper.select:
SELECT pr.id, pr.user_id, u.username, pr.product_id, p.name AS product_name, pr.order_item_id, pr.order_id, pr.rating, pr.content, pr.created_time FROM product_review pr LEFT JOIN `user` u ON pr.user_id = u.id AND u.deleted = 0 LEFT JOIN product p ON pr.product_id = p.id WHERE pr.product_id = #{productId}
AND pr.rating = #{rating}
ORDER BY pr.created_time DESC
